import{_ as t,o as s,c as e,ag as a}from"./chunks/framework.BOaOek6C.js";const g=JSON.parse('{"title":"Styles and Bootstrap","description":"","frontmatter":{},"headers":[],"relativePath":"addons/md/styles-and-bootstrap.md","filePath":"addons/md/styles-and-bootstrap.md"}'),r={name:"addons/md/styles-and-bootstrap.md"};function n(d,o,l,i,c,p){return s(),e("div",null,[...o[0]||(o[0]=[a('<h1 id="styles-and-bootstrap" tabindex="-1">Styles and Bootstrap <a class="header-anchor" href="#styles-and-bootstrap" aria-label="Permalink to &quot;Styles and Bootstrap&quot;">​</a></h1><h2 id="bootstrap" tabindex="-1">Bootstrap <a class="header-anchor" href="#bootstrap" aria-label="Permalink to &quot;Bootstrap&quot;">​</a></h2><p>The md addon bundles <strong>Bootstrap 5</strong> as <strong>SCSS</strong>. Applications that use md typically import its stylesheet so that:</p><ul><li>Utility classes (spacing, flex, borders, …) work as documented on <a href="https://getbootstrap.com/" target="_blank" rel="noreferrer">getbootstrap.com</a>.</li><li>Components such as <strong>collapse</strong> (show/hide panels) have matching CSS. The sidebar accordion uses the <strong><code>collapse</code> / <code>show</code></strong> classes; open/close is driven by <strong>Ember</strong> logic, not the Bootstrap JavaScript bundle.</li></ul><h2 id="custom-look" tabindex="-1">Custom look <a class="header-anchor" href="#custom-look" aria-label="Permalink to &quot;Custom look&quot;">​</a></h2><p>MdEditor-specific styling lives in SCSS partials under <strong><code>addons/md/addon/styles/</code></strong>, especially:</p><ul><li><strong><code>_app-shell.scss</code></strong> — shell, sidebars, primary nav, sidebar accordion, brand row.</li><li><strong><code>_variables.scss</code></strong> — overrides of Bootstrap variables (tokens) where needed.</li><li><strong><code>addon.scss</code></strong> — entry that pulls variables, Bootstrap, and app-shell.</li></ul><p>Changing colors or rail width is done here (or by extending these partials) rather than editing Bootstrap’s core files.</p><h2 id="icons" tabindex="-1">Icons <a class="header-anchor" href="#icons" aria-label="Permalink to &quot;Icons&quot;">​</a></h2><p>Icons in the chrome (e.g. dashboard, settings, sidebar chevron) come from <strong>Font Awesome</strong>, integrated via <strong><code>@fortawesome/ember-fontawesome</code></strong>. That is a <strong>dependency of the md addon</strong>, not a separate “service.”</p>',10)])])}const m=t(r,[["render",n]]);export{g as __pageData,m as default};
